args.query:
SELECT AVG(r.rating) AS avg_rating, COUNT(*) AS review_count
FROM review r
WHERE r.business_ref IN (
  SELECT 'businessref_' || substr(b.business_id, length('businessid_')+1)
  FROM (VALUES
    ('businessid_52'),('businessid_84'),('businessid_76'),('businessid_87'),('businessid_65')
  ) AS b(business_id)
);

